SELECT
e.*,
d.name AS departmentName
FROM t_employee e
LEFT JOIN t_department d ON d.department_id = e.department_id
LEFT JOIN t_oa_enterprise_employee ee on ee.employee_id = e.employee_id

    LEFT JOIN t_role_employee re ON re.employee_id = e.employee_id



        AND (
        INSTR(e.actual_name,#{queryForm.keyword})
        OR INSTR(e.phone,#{queryForm.keyword})
        OR INSTR(e.login_name,#{queryForm.keyword})
        )


        AND e.department_id = #{queryForm.departmentId}


        AND e.enterprise_id = #{queryForm.enterpriseId}


        AND e.department_id in

            #{item}



        AND e.disabled_flag = #{queryForm.disabledFlag}


        AND e.leave_flag = #{queryForm.leaveFlag}


        AND e.deleted_flag = #{queryForm.deletedFlag}


        AND re.role_id = #{queryForm.roleId}


GROUP BY e.employee_id

